import torch
import torch.nn as nn
from torch.utils.cpp_extension import load_inline
import math

# Define optimized fused kernel
fused_gelu_source = """
#include <torch/extension.h>
#include <cuda_runtime.h>
#include <cuda_fp16.h>

constexpr float GELU_COEF_A = 0.044715f;
constexpr float SQRT_2_OVER_PI = 0.7978845608028654f;

__device__ __forceinline__ float fast_gelu(float x) {
    // Fast GELU approximation: 0.5 * x * (1 + tanh(sqrt(2/pi) * (x + 0.044715 * x^3)))
    float x_cube = x * x * x;
    float inner = SQRT_2_OVER_PI * (x + GELU_COEF_A * x_cube);
    return 0.5f * x * (1.0f + tanhf(inner));
}

__global__ void fused_matmul_scale_gelu_kernel(
    const float* __restrict__ input,
    const float* __restrict__ weight,
    const float* __restrict__ bias,
    float* __restrict__ output,
    float divisor,
    int batch_size,
    int input_size,
    int output_size
) {
    // Each thread block computes a tile of output matrix
    const int TILE_SIZE = 32;

    // Thread indices
    int row = blockIdx.y * TILE_SIZE + threadIdx.y;
    int col = blockIdx.x * TILE_SIZE + threadIdx.x;

    // Shared memory for input and weight tiles
    __shared__ float input_tile[TILE_SIZE][TILE_SIZE];
    __shared__ float weight_tile[TILE_SIZE][TILE_SIZE];

    float result = 0.0f;

    // Loop over tiles
    for (int tile = 0; tile < (input_size + TILE_SIZE - 1) / TILE_SIZE; tile++) {
        // Load input tile
        int input_row = row;
        int input_col = tile * TILE_SIZE + threadIdx.x;
        if (input_row < batch_size && input_col < input_size) {
            input_tile[threadIdx.y][threadIdx.x] = input[input_row * input_size + input_col];
        } else {
            input_tile[threadIdx.y][threadIdx.x] = 0.0f;
        }

        // Load weight tile - TRANSPOSED ACCESS
        int weight_row = col;
        int weight_col = tile * TILE_SIZE + threadIdx.y;
        if (weight_row < output_size && weight_col < input_size) {
            // Weight is stored as [output_size, input_size], we need to access it properly
            weight_tile[threadIdx.y][threadIdx.x] = weight[weight_row * input_size + weight_col];
        } else {
            weight_tile[threadIdx.y][threadIdx.x] = 0.0f;
        }

        __syncthreads();

        // Compute partial dot product
        for (int k = 0; k < TILE_SIZE; k++) {
            result += input_tile[threadIdx.y][k] * weight_tile[k][threadIdx.x];
        }

        __syncthreads();
    }

    // Write result with bias, scaling, and GELU
    if (row < batch_size && col < output_size) {
        if (bias != nullptr) {
            result += bias[col];
        }
        result /= divisor;
        output[row * output_size + col] = fast_gelu(result);
    }
}

torch::Tensor fused_matmul_scale_gelu_cuda(
    torch::Tensor input,
    torch::Tensor weight,
    torch::Tensor bias,
    float divisor
) {
    int batch_size = input.size(0);
    int input_size = input.size(1);
    int output_size = weight.size(0);

    auto output = torch::empty({batch_size, output_size}, 
                              torch::TensorOptions().dtype(input.dtype()).device(input.device()));

    // Configure thread blocks
    const int TILE_SIZE = 32;
    dim3 block_size(TILE_SIZE, TILE_SIZE);
    dim3 grid_size((output_size + TILE_SIZE - 1) / TILE_SIZE,
                   (batch_size + TILE_SIZE - 1) / TILE_SIZE);

    // Launch kernel
    fused_matmul_scale_gelu_kernel<<<grid_size, block_size>>>(
        input.data_ptr<float>(),
        weight.data_ptr<float>(),
        bias.defined() ? bias.data_ptr<float>() : nullptr,
        output.data_ptr<float>(),
        divisor,
        batch_size,
        input_size,
        output_size
    );

    cudaDeviceSynchronize();
    cudaError_t err = cudaGetLastError();
    if (err != cudaSuccess) {
        throw std::runtime_error(cudaGetErrorString(err));
    }

    return output;
}
"""

fused_gelu_cpp_source = """
torch::Tensor fused_matmul_scale_gelu_cuda(
    torch::Tensor input,
    torch::Tensor weight,
    torch::Tensor bias,
    float divisor
);
"""

# Compile the inline CUDA code
fused_gelu = load_inline(
    name="fused_gelu",
    cpp_sources=fused_gelu_cpp_source,
    cuda_sources=fused_gelu_source,
    functions=["fused_matmul_scale_gelu_cuda"],
    verbose=False
)

class ModelNew(nn.Module):
    """
    Optimized model with fused matmul + scale + GELU CUDA kernel.
    """
    def __init__(self, input_size, output_size, divisor):
        super(ModelNew, self).__init__()
        self.input_size = input_size
        self.output_size = output_size
        self.divisor = divisor

        # Initialize weights and bias
        self.weight = nn.Parameter(torch.empty(output_size, input_size))
        self.bias = nn.Parameter(torch.empty(output_size))

        # Initialize parameters
        nn.init.kaiming_uniform_(self.weight, a=math.sqrt(5))
        fan_in, _ = nn.init._calculate_fan_in_and_fan_out(self.weight)
        bound = 1 / math.sqrt(fan_in) if fan_in > 0 else 0
        nn.init.uniform_(self.bias, -bound, bound)

        # Store the fused kernel
        self.fused_gelu = fused_gelu

    def forward(self, x):
        """
        Args:
            x (torch.Tensor): Input tensor of shape (batch_size, input_size).
        Returns:
            torch.Tensor: Output tensor of shape (batch_size, output_size).
        """
        return self.fused_gelu.fused_matmul_scale_gelu_cuda(
            x, 
            self.weight, 
            self.bias, 
            self.divisor
        )

