fused_gelu_source = """
#include <torch/extension.h>
#include <cuda_runtime.h>
#include <cuda_fp16.h>

constexpr float GELU_COEF_A = 0.044715f;
constexpr float SQRT_2_OVER_PI = 0.7978845608028654f;

__device__ __forceinline__ float fast_gelu(float x) {
    // Fast GELU approximation: 0.5 * x * (1 + tanh(sqrt(2/pi) * (x + 0.044715 * x^3)))
    float x_cube = x * x * x;
    float inner = SQRT_2_OVER_PI * (x + GELU_COEF_A * x_cube);
    return 0.5f * x * (1.0f + tanhf(inner));
}

__global__ void fused_matmul_scale_gelu_kernel(
    const float* __restrict__ input,
    const float* __restrict__ weight,
    const float* __restrict__ bias,
    float* __restrict__ output,
    float divisor,
    int batch_size,
    int input_size,
    int output_size
) {
    // Each thread block computes a tile of output matrix
    const int TILE_SIZE = 32;

    // Thread indices
    int row = blockIdx.y * TILE_SIZE + threadIdx.y;
    int col = blockIdx.x * TILE_SIZE + threadIdx.x;

    // Shared memory for input and weight tiles
    __shared__ float input_tile[TILE_SIZE][TILE_SIZE];
    __shared__ float weight_tile[TILE_SIZE][TILE_SIZE];

    float result = 0.0f;

    // Loop over tiles
    for (int tile = 0; tile < (input_size + TILE_SIZE - 1) / TILE_SIZE; tile++) {
        // Load input tile
        int input_row = row;
        int input_col = tile * TILE_SIZE + threadIdx.x;
        if (input_row < batch_size && input_col < input_size) {
            input_tile[threadIdx.y][threadIdx.x] = input[input_row * input_size + input_col];
        } else {
            input_tile[threadIdx.y][threadIdx.x] = 0.0f;
        }

        // Load weight tile - TRANSPOSED ACCESS
        int weight_row = col;
        int weight_col = tile * TILE_SIZE + threadIdx.y;
        if (weight_row < output_size && weight_col < input_size) {
            // Weight is stored as [output_size, input_size], we need to access it properly
            weight_tile[threadIdx.y][threadIdx.x] = weight[weight_row * input_size + weight_col];
        } else {
            weight_tile[threadIdx.y][threadIdx.x] = 0.0f;
        }

        __syncthreads();

        // Compute partial dot product
        for (int k = 0; k < TILE_SIZE; k++) {
            result += input_tile[threadIdx.y][k] * weight_tile[k][threadIdx.x];
        }

        __syncthreads();
    }

    // Write result with bias, scaling, and GELU
    if (row < batch_size && col < output_size) {
        if (bias != nullptr) {
            result += bias[col];
        }
        result /= divisor;
        output[row * output_size + col] = fast_gelu(result);
    }
